import React, { useEffect, useState, useCallback } from 'react';
import api from '../api';
import { formatDistanceToNow } from 'date-fns';
import './Notifications.css';

export default function Notifications() {
  const [notifications, setNotifications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [marking, setMarking] = useState(false);

  const fetchNotifications = useCallback(async () => {
    try {
      const res = await api.get('/notifications');
      setNotifications(res.data.notifications);
    } catch {}
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    fetchNotifications();
    const interval = setInterval(fetchNotifications, 10000);
    return () => clearInterval(interval);
  }, [fetchNotifications]);

  const markRead = async (id) => {
    await api.put(`/notifications/${id}/read`);
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: 1 } : n));
  };

  const markAllRead = async () => {
    setMarking(true);
    try {
      await api.put('/notifications/read-all');
      setNotifications(prev => prev.map(n => ({ ...n, read: 1 })));
    } finally {
      setMarking(false);
    }
  };

  const unreadCount = notifications.filter(n => n.read === 0).length;

  if (loading) return (
    <div className="page-container" style={{ textAlign: 'center', paddingTop: '4rem' }}>
      <span className="spinner" style={{ width: 36, height: 36 }} />
    </div>
  );

  return (
    <div className="page-container">
      <div className="notif-page-header">
        <h1 className="page-title" style={{ marginBottom: 0 }}>
          🔔 Notifications
          {unreadCount > 0 && <span className="unread-count">{unreadCount} new</span>}
        </h1>
        {unreadCount > 0 && (
          <button className="btn btn-secondary" onClick={markAllRead} disabled={marking}>
            {marking ? <span className="spinner" /> : 'Mark all as read'}
          </button>
        )}
      </div>

      <div className="card">
        {notifications.length === 0 ? (
          <div className="empty-notif">
            <span className="empty-icon">🔕</span>
            <p>No notifications yet.</p>
            <p>You'll be notified when blood requests match your profile or when donors respond.</p>
          </div>
        ) : (
          <div className="notif-list">
            {notifications.map(n => (
              <div
                key={n.id}
                className={`notif-item ${n.read === 0 ? 'unread' : ''}`}
                onClick={() => n.read === 0 && markRead(n.id)}
              >
                <div className="notif-dot-wrap">
                  {n.read === 0 && <span className="notif-dot" />}
                </div>
                <div className="notif-content">
                  <p className="notif-message">{n.message}</p>
                  <span className="notif-time">
                    {formatDistanceToNow(new Date(n.created_at), { addSuffix: true })}
                  </span>
                </div>
                {n.read === 0 && (
                  <button
                    className="mark-read-btn"
                    onClick={(e) => { e.stopPropagation(); markRead(n.id); }}
                  >
                    ✓
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
